--
-- Structure for view `v_employee_performance`
--
DROP TABLE IF EXISTS `v_employee_performance`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_employee_performance`  AS SELECT `e`.`employee_id` AS `employee_id`, `e`.`employee_name` AS `employee_name`, `d`.`dept_name` AS `dept_name`, count(`t`.`id`) AS `total_tasks`, sum(`t`.`status` = 'completed') AS `completed_tasks`, round(sum(`t`.`status` = 'completed') / count(`t`.`id`) * 100,2) AS `completion_rate`, round(avg(timestampdiff(HOUR,`t`.`assigned_at`,`t`.`completed_at`)),2) AS `avg_hours` FROM ((`production_tasks` `t` join `employees` `e` on(`e`.`employee_id` = `t`.`assigned_to_employee_id`)) join `departments` `d` on(`d`.`dept_id` = `e`.`department_id`)) GROUP BY `e`.`employee_id` ;

-- --------------------------------------------------------

--
-- Structure for view `v_material_costs`
--
DROP TABLE IF EXISTS `v_material_costs`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_material_costs`  AS SELECT `m`.`department_id` AS `department_id`, sum(`m`.`actual_cost`) AS `total_actual_cost`, sum(`m`.`estimated_cost`) AS `total_estimated_cost`, count(`m`.`id`) AS `total_requests`, month(`m`.`created_at`) AS `month` FROM `production_tasks_material_requests` AS `m` GROUP BY `m`.`department_id`, month(`m`.`created_at`) ;

-- --------------------------------------------------------

--
-- Structure for view `v_tasks_summary`
--
DROP TABLE IF EXISTS `v_tasks_summary`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_tasks_summary`  AS SELECT `t`.`id` AS `id`, `d`.`dept_name` AS `dept_name`, `e`.`employee_name` AS `employee_name`, `t`.`status` AS `status`, timestampdiff(HOUR,`t`.`assigned_at`,`t`.`completed_at`) AS `duration_hours`, `t`.`estimated_cost` AS `estimated_cost`, `t`.`completed_at` AS `completed_at`, `t`.`department_id` AS `department_id`, `t`.`assigned_to_employee_id` AS `assigned_to_employee_id` FROM ((`production_tasks` `t` left join `departments` `d` on(`d`.`dept_id` = `t`.`department_id`)) left join `employees` `e` on(`e`.`employee_id` = `t`.`assigned_to_employee_id`)) ;

