--
-- Structure for view `v_task_last_handoff_qa`
--
DROP TABLE IF EXISTS `v_task_last_handoff_qa`;

CREATE ALGORITHM=UNDEFINED DEFINER=`aelsayed`@`localhost` SQL SECURITY DEFINER VIEW `v_task_last_handoff_qa`  AS SELECT `l`.`task_id` AS `task_id`, substring_index(group_concat(`l`.`type` order by coalesce(`l`.`happened_at`,`l`.`created_at`) DESC separator ','),',',1) AS `last_qa_handoff` FROM `production_tasks_log` AS `l` WHERE `l`.`type` in ('manufacturing_sent_to_qa','installation_sent_to_qa','sent_to_quality') GROUP BY `l`.`task_id` ;

