DROP TABLE IF EXISTS `v_task_last_log`;

CREATE ALGORITHM=UNDEFINED DEFINER=`aelsayed`@`localhost` SQL SECURITY DEFINER VIEW `v_task_last_log`  AS SELECT `l`.`task_id` AS `task_id`, substring_index(group_concat(`l`.`type` order by coalesce(`l`.`happened_at`,`l`.`created_at`) DESC separator ','),',',1) AS `last_type`, max(coalesce(`l`.`happened_at`,`l`.`created_at`)) AS `last_at` FROM `production_tasks_log` AS `l` GROUP BY `l`.`task_id` ;

